11	// RunnerDockerImage is the container image used for docker-mode runners.
12	const RunnerDockerImage = "ghcr.io/actions/actions-runner:latest"
13	
14	// dockerRunnerEntryScript registers once (registration tokens are single-use) then runs the
15	// listener. Official ghcr.io/actions/actions-runner has no CMD; it expects config.sh then run.sh.
16	const dockerRunnerEntryScript = `cd /home/runner && if [ ! -f .runner ]; then ./config.sh --unattended --replace; fi && exec ./run.sh`
17	
18	// ContainerName returns the Docker container name for a runner instance.
19	func ContainerName(instanceName string) string {
20		return "gh-runner-" + instanceName
21	}
22	
23	func containerName(instanceName string) string {
24		return ContainerName(instanceName)
25	}
26	
27	// shellSingleQuote wraps s in single quotes for a POSIX shell word (safe for docker -e on Linux/macOS SSH).
28	func shellSingleQuote(s string) string {
29		return "'" + strings.ReplaceAll(s, "'", "'\\''") + "'"
30	}
31	
32	// dockerEnvFlag renders one -e flag as a single shell word: -e 'NAME=value'
33	func dockerEnvFlag(name, value string) string {
34		return "-e " + shellSingleQuote(name+"="+value)
35	}
36	
37	// dockerStartCommand builds the docker run line for the official actions-runner image (config.sh + run.sh).
38	func dockerStartCommand(cname, instanceName, regToken, repoURL, labels, sockMount, image string) string {
39		var b strings.Builder
40		fmt.Fprintf(&b, "docker run -d --name %s --restart unless-stopped ", cname)
41		b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_URL", repoURL))
42		b.WriteByte(' ')
43		b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_TOKEN", regToken))
44		b.WriteByte(' ')
45		b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_NAME", instanceName))
46		b.WriteByte(' ')
47		b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_LABELS", labels))
48		b.WriteByte(' ')
49		b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_WORK", "_work"))
50		b.WriteByte(' ')
51		if s := strings.TrimSpace(sockMount); s != "" {
52			b.WriteString(s)
53			b.WriteByte(' ')
54		}
55		b.WriteString("--entrypoint /bin/bash ")
56		b.WriteString(image)
57		b.WriteString(" -c ")
58		b.WriteString(shellSingleQuote(dockerRunnerEntryScript))
59		return b.String()
60	}
61	
62	// DefaultDockerSocket is the conventional Docker daemon socket path on Linux and macOS hosts.
63	const DefaultDockerSocket = "/var/run/docker.sock"
64	
65	// defaultDockerSocket is an unexported alias kept for internal use within this package.
66	const defaultDockerSocket = DefaultDockerSocket
67	
68	// socketPathFromDockerContextHost returns the filesystem path when endpoint is a unix:// Docker API URL.
69	func socketPathFromDockerContextHost(endpoint string) (path string, ok bool) {
70		endpoint = strings.TrimSpace(endpoint)
71		if endpoint == "" {
72			return "", false
73		}
74		if !strings.HasPrefix(endpoint, "unix://") {
75			return "", false
76		}
77		path = strings.TrimPrefix(endpoint, "unix://")
78		if path == "" || path[0] != '/' {
79			return "", false
80		}
81		return path, true
82	}
83	
84	func remoteDockerSocketOK(h *host.Host, path string) (bool, error) {
85		q := shellSingleQuote(path)
86		out, err := h.Run(fmt.Sprintf("test -S %s && echo ok || echo missing", q))
87		if err != nil {
88			return false, err
89		}
90		return strings.TrimSpace(out) == "ok", nil
91	}
92	
93	// EffectiveDockerSocket returns the host-side Docker socket path for bind-mounting on Linux and macOS.
94	// When HostConfig.DockerSocket is set, that path is used if it exists. Otherwise ghr probes, in order:
95	// /var/run/docker.sock, the active docker context unix endpoint (Colima, rootless Docker, etc.),
96	// and on macOS ~/.colima/default/docker.sock.
97	func EffectiveDockerSocket(h *host.Host) (string, error) {
98		if h.OS != "linux" && h.OS != "darwin" {
99			return "", fmt.Errorf("EffectiveDockerSocket: unsupported OS %q", h.OS)
100		}
101		if p := strings.TrimSpace(h.DockerSocket); p != "" {
102			ok, err := remoteDockerSocketOK(h, p)
103			if err != nil {
104				return "", fmt.Errorf("checking docker_socket on host %s: %w", h.Name, err)
105			}
106			if !ok {
107				return "", fmt.Errorf("docker_socket not found or not a socket at %s on host %s", p, h.Name)
108			}
109			return p, nil
110		}
111		ok, err := remoteDockerSocketOK(h, defaultDockerSocket)
112		if err != nil {
113			return "", fmt.Errorf("checking Docker socket on host %s: %w", h.Name, err)
114		}
115		if ok {
116			return defaultDockerSocket, nil
117		}
118		ctxOut, derr := dockerRun(h, `docker context inspect -f '{{.Endpoints.docker.Host}}'`)
119		if derr == nil {
120			if p, parseOK := socketPathFromDockerContextHost(ctxOut); parseOK {
121				ok2, err2 := remoteDockerSocketOK(h, p)
122				if err2 != nil {
123					return "", fmt.Errorf("checking Docker socket from context on host %s: %w", h.Name, err2)
124				}
125				if ok2 {
126					return p, nil
127				}
128			}
129		}
130		if h.OS == "darwin" {
131			out, rerr := h.Run(prependDarwinDockerPATH(h, `p="$HOME/.colima/default/docker.sock"; if test -S "$p"; then printf '%s' "$p"; fi`))
132			if rerr == nil {
133				if p := strings.TrimSpace(out); p != "" {
134					return p, nil
135				}
136			}
137		}
138		hint := "ensure Docker is running (rootless Docker: ghr uses your default docker context; set docker_socket to override)"
139		if h.OS == "darwin" {
140			hint = "ensure Docker Desktop/OrbStack/Colima is running, or set docker_socket for a non-default socket path"
141		}
142		return "", fmt.Errorf("no usable Docker socket found on host %s; %s", h.Name, hint)
143	}
144	
145	// dockerEngineSockFlags returns the docker run flags needed to expose the host Docker socket inside
146	// a Linux actions-runner container and grant the container's runner user access to it.
147	//
148	// It returns both a -v bind-mount and a --group-add <GID> flag. The GID is read from the host
149	// socket's owning group via `stat -c '%g'`; this avoids "permission denied" when the container's
150	// runner user (uid 1001) is not in the host docker group. If the GID cannot be determined, only
151	// the mount is returned (best-effort; caller may still get EACCES at runtime).
152	//
153	// socketPath is the host-side socket (from HostConfig.DockerSocket, defaulting to /var/run/docker.sock).
154	// The container-side path is always /var/run/docker.sock so job scripts use the default DOCKER_HOST.
155	func dockerEngineSockFlags(h *host.Host, socketPath string) string {
156		if socketPath == "" {
157			socketPath = defaultDockerSocket
158		}
159		mount := fmt.Sprintf("-v %s:/var/run/docker.sock ", socketPath)
160	
161		// Query the GID that owns the socket on the host so we can pass --group-add.
162		out, err := h.Run(fmt.Sprintf("stat -c '%%g' %s 2>/dev/null", socketPath))
163		gid := strings.TrimSpace(out)
164		if err != nil || gid == "" || gid == "0" {
165			// GID 0 means root owns it and no special group; skip --group-add (no benefit or unknown).
166			return mount
167		}
168		return mount + fmt.Sprintf("--group-add %s ", gid)
169	}
170	
171	// darwinDockerSockFlags returns the docker run flags to bind-mount the Docker socket on a macOS
172	// host. On macOS (Docker Desktop, OrbStack, Colima) the socket is accessible to all processes
173	// inside the VM — there is no docker group GID mismatch — so only the -v mount is needed.
174	//
175	// socketPath is the host-side socket (from HostConfig.DockerSocket, defaulting to /var/run/docker.sock).
176	func darwinDockerSockFlags(socketPath string) string {
177		if socketPath == "" {
178			socketPath = defaultDockerSocket
179		}
180		return fmt.Sprintf("-v %s:/var/run/docker.sock ", socketPath)
181	}
182	
183	// dockerWindowsEngineSockMount is the bind-mount for the Docker engine socket on Windows hosts
184	// (Docker Desktop Linux engine; path is resolved inside the Hyper-V/WSL2 VM).
185	const dockerWindowsEngineSockMount = "-v /var/run/docker.sock:/var/run/docker.sock "
186	
187	// dockerWindowsSockGIDProbeCommand returns the docker CLI line to read the owning GID of
188	// /var/run/docker.sock inside the Docker Desktop Linux engine. Uses sh+stat because the runner
189	// image has no one-shot default CMD suitable for stat.
190	func dockerWindowsSockGIDProbeCommand(image string) string {
191		return fmt.Sprintf(
192			`docker run --rm -v /var/run/docker.sock:/var/run/docker.sock --entrypoint sh %s -c "stat -c '%%g' /var/run/docker.sock"`,
193			image,
194		)
195	}
196	
197	// appendGroupAddForDockerSockGID appends --group-add when probe output is a non-zero numeric GID.
198	func appendGroupAddForDockerSockGID(mount, gidProbeOutput string) string {
199		gid := strings.TrimSpace(gidProbeOutput)
200		if gid == "" || gid == "0" {
201			return mount
202		}
203		for _, c := range gid {
204			if c < '0' || c > '9' {
205				return mount
206			}
207		}
208		return mount + fmt.Sprintf("--group-add %s ", gid)
209	}
210	
211	// dockerEngineSockFlagsWindows returns docker run flags for the Docker socket on a Windows host
212	// running Docker Desktop (Linux containers mode). The socket lives in the Linux engine VM; we
213	// probe its group GID via a disposable container because Windows has no Unix stat on that path.
214	func dockerEngineSockFlagsWindows(h *host.Host) string {
215		out, err := dockerRun(h, dockerWindowsSockGIDProbeCommand(RunnerDockerImage)+` 2>$null`)
216		if err != nil {
217			return dockerWindowsEngineSockMount
218		}
219		return appendGroupAddForDockerSockGID(dockerWindowsEngineSockMount, out)
220	}
221	
222	// dockerEngineSockPreflightCheck verifies the socket path is present and is a socket on the host
223	// before docker run. Returns an error with an actionable message if the socket is missing.
224	func dockerEngineSockPreflightCheck(h *host.Host, socketPath string) error {
225		if socketPath == "" {
226			socketPath = defaultDockerSocket
227		}
228		out, err := h.Run(fmt.Sprintf("test -S %s && echo ok || echo missing", socketPath))
229		if err != nil {
230			return fmt.Errorf("checking Docker socket %s on host: %w", socketPath, err)
231		}
232		if strings.TrimSpace(out) != "ok" {
233			msg := fmt.Sprintf(
234				"Docker socket not found at %s on host %s; ensure Docker is installed and running (or set docker_socket in config for rootless Docker)",
235				socketPath, h.Name,
236			)
237			return fmt.Errorf("%s", msg)
238		}
239		return nil
240	}
