242	// prependDarwinDockerPATH prefixes a remote shell command on macOS so the Docker CLI is on PATH
243	// when SSH uses a minimal environment (missing /usr/local/bin and /opt/homebrew/bin).
244	func prependDarwinDockerPATH(h *host.Host, cmd string) string {
245		if h.OS != "darwin" {
246			return cmd
247		}
248		return `export PATH="/usr/local/bin:/opt/homebrew/bin:$PATH"; ` + cmd
249	}
250	
251	// dockerRun executes a Docker CLI command on the host, using PowerShell
252	// wrapping on Windows and raw shell on Linux/macOS.
253	func dockerRun(h *host.Host, cmd string) (string, error) {
254		if h.OS == "windows" {
255			return h.RunShell(windowsDockerCommand(cmd))
256		}
257		return h.Run(prependDarwinDockerPATH(h, cmd))
258	}
259	
260	// dockerRunIgnoreErr is like dockerRun but discards the error (for best-effort cleanup).
261	func dockerRunIgnoreErr(h *host.Host, cmd string) {
262		if h.OS == "windows" {
263			h.RunShell(windowsDockerCommand(cmd))
264		} else {
265			h.Run(prependDarwinDockerPATH(h, cmd))
266		}
267	}
