269	func (m *Manager) setupDocker(h *host.Host) error {
270		if h.OS == "windows" {
271			return m.setupDockerWindows(h)
272		}
273		return m.setupDockerUnix(h)
274	}
275	
276	// windowsDockerCommand forces Docker to use an isolated config directory that
277	// avoids the Windows native credential helper in SSH sessions. The dummy auth
278	// entry keeps Docker CLI from auto-detecting wincred as the default store when
279	// no auth is configured.
280	func windowsDockerCommand(cmd string) string {
281		return strings.TrimSpace(fmt.Sprintf(`
282	$ghrDockerConfigDir = Join-Path $env:TEMP 'ghr-docker-config'
283	New-Item -ItemType Directory -Force -Path $ghrDockerConfigDir | Out-Null
284	$ghrDockerConfigFile = Join-Path $ghrDockerConfigDir 'config.json'
285	$ghrDockerConfigJson = @'
286	{
287	  "auths": {
288	    "ghr.invalid": {
289	      "auth": "Z2hyOmdocg=="
290	    }
291	  },
292	  "credsStore": ""
293	}
294	'@
295	[System.IO.File]::WriteAllText($ghrDockerConfigFile, $ghrDockerConfigJson, [System.Text.UTF8Encoding]::new($false))
296	$env:DOCKER_CONFIG = $ghrDockerConfigDir
297	%s
298	`, cmd))
299	}
300	
301	func (m *Manager) setupDockerWindows(h *host.Host) error {
302		out, err := dockerRun(h, `docker info --format "{{.ServerVersion}}"`)
303		if err != nil || strings.TrimSpace(out) == "" {
304			return fmt.Errorf("docker not available on host %s: install Docker Desktop and ensure it is running", h.Name)
305		}
306		fmt.Fprintf(m.out(), "  %s: Docker %s available\n", h.Name, strings.TrimSpace(out))
307	
308		fmt.Fprintf(m.out(), "  %s: pulling runner image...\n", h.Name)
309		if _, err := dockerRun(h, fmt.Sprintf("docker pull %s", RunnerDockerImage)); err != nil {
310			return fmt.Errorf("pulling Docker image: %w", err)
311		}
312	
313		return nil
314	}
315	
316	// UnixDockerCLIInstalled reports whether a docker binary exists on PATH on the host.
317	func UnixDockerCLIInstalled(h *host.Host) (bool, error) {
318		out, err := h.Run(prependDarwinDockerPATH(h, `if command -v docker >/dev/null 2>&1; then echo yes; else echo no; fi`))
319		if err != nil {
320			return false, err
321		}
322		switch strings.TrimSpace(out) {
323		case "yes":
324			return true, nil
325		case "no":
326			return false, nil
327		default:
328			return false, fmt.Errorf("unexpected output checking docker CLI: %q", out)
329		}
330	}
331	
332	func wrapDockerInfoErr(err error) error {
333		if err == nil {
334			return nil
335		}
336		lower := strings.ToLower(err.Error())
337		switch {
338		case strings.Contains(lower, "permission denied") && strings.Contains(lower, "docker.sock"):
339			return fmt.Errorf("cannot access Docker socket (add the SSH user to the 'docker' group and reconnect SSH, or use root): %w", err)
340		case strings.Contains(lower, "permission denied"):
341			return fmt.Errorf("permission denied talking to Docker: %w", err)
342		case strings.Contains(lower, "cannot connect to the docker daemon"),
343			strings.Contains(lower, "is the docker daemon running"),
344			strings.Contains(lower, "connection refused"):
345			return fmt.Errorf("Docker daemon not reachable (start the Docker service, e.g. systemctl start docker; see README): %w", err)
346		default:
347			return err
348		}
349	}
350	
351	// UnixDockerServerVersion returns the Docker Engine server version from docker info, or an error
352	// that distinguishes socket permissions and daemon reachability from other failures.
353	func UnixDockerServerVersion(h *host.Host) (string, error) {
354		out, err := h.Run(prependDarwinDockerPATH(h, "docker info --format '{{.ServerVersion}}'"))
355		out = strings.TrimSpace(out)
356		if err == nil {
357			if out == "" {
358				return "", fmt.Errorf("docker info returned empty server version")
359			}
360			return out, nil
361		}
362		return "", wrapDockerInfoErr(err)
363	}
