365	func (m *Manager) setupDockerUnix(h *host.Host) error {
366		hasCLI, err := UnixDockerCLIInstalled(h)
367		if err != nil {
368			return fmt.Errorf("checking docker on host %s: %w", h.Name, err)
369		}
370	
371		if hasCLI {
372			out, verr := UnixDockerServerVersion(h)
373			if verr == nil {
374				fmt.Fprintf(m.out(), "  %s: Docker %s available\n", h.Name, out)
375				fmt.Fprintf(m.out(), "  %s: pulling runner image...\n", h.Name)
376				if _, err := dockerRun(h, fmt.Sprintf("docker pull %s", RunnerDockerImage)); err != nil {
377					return fmt.Errorf("pulling Docker image: %w", err)
378				}
379				return nil
380			}
381			if h.OS == "darwin" {
382				return fmt.Errorf(
383					"docker not available on host %s: install Docker Desktop, OrbStack, or Colima and ensure the Docker CLI works in your SSH session: %w",
384					h.Name, verr,
385				)
386			}
387			return fmt.Errorf("docker on host %s is not usable: %w", h.Name, verr)
388		}
389	
390		if h.OS == "darwin" {
391			return fmt.Errorf(
392				"docker not available on host %s: install Docker Desktop, OrbStack, or Colima and ensure the Docker CLI works in your SSH session",
393				h.Name,
394			)
395		}
396	
397		fmt.Fprintf(m.out(), "  %s: Docker not found, attempting to install...\n", h.Name)
398		installCmd := linuxElevatePrelude + `
399				if ! command -v curl >/dev/null 2>&1; then
400					if command -v apt-get >/dev/null 2>&1; then $SUDO apt-get update && $SUDO apt-get install -y curl;
401					elif command -v yum >/dev/null 2>&1; then $SUDO yum install -y curl;
402					elif command -v apk >/dev/null 2>&1; then $SUDO apk add curl;
403					fi
404				fi &&
405				curl -fsSL https://get.docker.com | $SUDO sh
406			`
407		if _, instErr := h.Run(installCmd); instErr != nil {
408			return fmt.Errorf(
409				"failed to install docker on host %s (need root SSH, passwordless sudo, or install Docker manually; see ghr doctor): %w",
410				h.Name, instErr,
411			)
412		}
413	
414		hasCLI, err = UnixDockerCLIInstalled(h)
415		if err != nil {
416			return fmt.Errorf("rechecking docker on host %s: %w", h.Name, err)
417		}
418		if !hasCLI {
419			return fmt.Errorf("docker still not installed on host %s after installation attempt", h.Name)
420		}
421		out, verr := UnixDockerServerVersion(h)
422		if verr != nil {
423			return fmt.Errorf("docker installed on host %s but still not usable (e.g. add user to 'docker' group and reconnect SSH): %w", h.Name, verr)
424		}
425		fmt.Fprintf(m.out(), "  %s: Docker %s available\n", h.Name, out)
426	
427		fmt.Fprintf(m.out(), "  %s: pulling runner image...\n", h.Name)
428		if _, err := dockerRun(h, fmt.Sprintf("docker pull %s", RunnerDockerImage)); err != nil {
429			return fmt.Errorf("pulling Docker image: %w", err)
430		}
431	
432		return nil
433	}
