435	func (m *Manager) startDocker(h *host.Host, rc config.RunnerConfig, instanceName string) error {
436		cname := containerName(instanceName)
437	
438		if h.OS == "windows" {
439			running, _ := dockerRun(h, fmt.Sprintf(`docker inspect -f "{{.State.Running}}" %s 2>$null`, cname))
440			if strings.TrimSpace(running) == "true" {
441				fmt.Fprintf(m.out(), "  %s: already running\n", instanceName)
442				return nil
443			}
444			dockerRunIgnoreErr(h, fmt.Sprintf("docker rm -f %s 2>$null", cname))
445		} else {
446			running, _ := dockerRun(h, fmt.Sprintf("docker inspect -f '{{.State.Running}}' %s 2>/dev/null", cname))
447			if strings.TrimSpace(running) == "true" {
448				fmt.Fprintf(m.out(), "  %s: already running\n", instanceName)
449				return nil
450			}
451			dockerRunIgnoreErr(h, fmt.Sprintf("docker rm -f %s 2>/dev/null || true", cname))
452		}
453	
454		regToken, err := m.GitHub.GetRegistrationToken(rc.Repo)
455		if err != nil {
456			return err
457		}
458	
459		labels := strings.Join(rc.Labels, ",")
460		repoURL := fmt.Sprintf("https://github.com/%s", rc.Repo)
461	
462		var sockFlags string
463		switch h.OS {
464		case "linux", "darwin":
465			sockPath, err := EffectiveDockerSocket(h)
466			if err != nil {
467				return err
468			}
469			if h.OS == "linux" {
470				sockFlags = dockerEngineSockFlags(h, sockPath)
471			} else {
472				sockFlags = darwinDockerSockFlags(sockPath)
473			}
474		case "windows":
475			// Docker Desktop (Linux containers mode): bind-mount the engine socket and match Linux
476			// behavior by adding --group-add for the socket's GID when we can probe it from a disposable container.
477			sockFlags = dockerEngineSockFlagsWindows(h)
478		}
479	
480		cmd := dockerStartCommand(cname, instanceName, regToken, repoURL, labels, sockFlags, RunnerDockerImage)
481	
482		out, err := dockerRun(h, cmd)
483		if err != nil {
484			return fmt.Errorf("starting Docker container: %w", err)
485		}
486	
487		containerID := strings.TrimSpace(out)
488		if len(containerID) > 12 {
489			containerID = containerID[:12]
490		}
491		fmt.Fprintf(m.out(), "  %s: started (container %s)\n", instanceName, containerID)
492		return nil
493	}
494	
495	func (m *Manager) stopDocker(h *host.Host, instanceName string) error {
496		cname := containerName(instanceName)
497	
498		var inspectCmd string
499		if h.OS == "windows" {
500			inspectCmd = fmt.Sprintf(`docker inspect -f "{{.State.Running}}" %s 2>$null`, cname)
501		} else {
502			inspectCmd = fmt.Sprintf("docker inspect -f '{{.State.Running}}' %s 2>/dev/null", cname)
503		}
504		running, _ := dockerRun(h, inspectCmd)
505		if strings.TrimSpace(running) != "true" {
506			fmt.Fprintf(m.out(), "  %s: not running\n", instanceName)
507			return nil
508		}
509	
510		if _, err := dockerRun(h, fmt.Sprintf("docker stop -t 30 %s", cname)); err != nil {
511			return fmt.Errorf("stopping container: %w", err)
512		}
513	
514		fmt.Fprintf(m.out(), "  %s: stopped\n", instanceName)
515		return nil
516	}
517	
518	func (m *Manager) removeDocker(h *host.Host, instanceName string) error {
519		cname := containerName(instanceName)
520	
521		_ = m.stopDocker(h, instanceName)
522	
523		var rmCmd string
524		if h.OS == "windows" {
525			rmCmd = fmt.Sprintf("docker rm -f %s 2>$null", cname)
526		} else {
527			rmCmd = fmt.Sprintf("docker rm -f %s 2>/dev/null || true", cname)
528		}
529		if _, err := dockerRun(h, rmCmd); err != nil {
530			return fmt.Errorf("removing container: %w", err)
531		}
532	
533		fmt.Fprintf(m.out(), "  %s: removed\n", instanceName)
534		return nil
535	}
