537	func (m *Manager) statusDocker(h *host.Host, instanceName string) string {
538		cname := containerName(instanceName)
539	
540		var inspectCmd string
541		if h.OS == "windows" {
542			inspectCmd = fmt.Sprintf(`docker inspect -f "{{.State.Status}}" %s 2>$null`, cname)
543		} else {
544			inspectCmd = fmt.Sprintf("docker inspect -f '{{.State.Status}}' %s 2>/dev/null", cname)
545		}
